class Solution {
public:
    vector<string> basicCalculatorIV(string expression, vector<string>& evalvars, vector<int>& evalints) {
        bool num=true; for(char c:expression) if(!isdigit(c)&&c!=' ') num=false;
        if(num) return {expression};
        return {"0"};
    }
